		return []*SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = sessionKey(id)
	}

	results, err := r.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to load sandboxes: %w", err)
	}

	sandboxes := make([]*SandboxInfo, 0, len(sessionIDs))
	for i, result := range results {
		if result == nil {
			continue
		}

		var sandbox SandboxInfo
		if err := json.Unmarshal([]byte(result.(string)), &sandbox); err != nil {
			klog.Warningf("failed to unmarshal sandbox %s: %v", sessionIDs[i], err)
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

func sessionKey(sessionID string) string {
	return SessionKeyPrefix + sessionID
}

package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/agentcube/agentcube/pkg/store"
	"github.com/gin-gonic/gin"
	"k8s.io/client-go/dynamic"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

type Server struct {
	config         *Config
	httpServer     *http.Server
	store          store.Store
	k8sClient      kubernetes.Interface
	dynamicClient  dynamic.Interface
	authCache      *AuthCache
	gcStopChan     chan struct{}
	gcWg           sync.WaitGroup
}

type AuthCache struct {
	cache map[string]*AuthCacheEntry
	mu    sync.RWMutex
	ttl   time.Duration
}

type AuthCacheEntry struct {
	token     string
	username  string
	saName    string
	namespace string
	expiresAt time.Time
}

func NewServer(config *Config) (*Server, error) {
	k8sClient, err := kubernetes.NewForConfig(getKubeConfig())
	if err != nil {
		return nil, fmt.Errorf("failed to create k8s client: %w", err)
	}

	dynamicClient, err := dynamic.NewForConfig(getKubeConfig())
	if err != nil {
		return nil, fmt.Errorf("failed to create dynamic client: %w", err)
	}

	s := &Server{
		config:        config,
		store:         store.Storage(),
		k8sClient:     k8sClient,
		dynamicClient: dynamicClient,
		authCache: &AuthCache{
			cache: make(map[string]*AuthCacheEntry),
			ttl:   5 * time.Minute,
		},
		gcStopChan: make(chan struct{}),
	}

	s.setupRouter()

	return s, nil
}

func (s *Server) setupRouter() {
	engine := gin.New()
	engine.Use(gin.Logger(), gin.Recovery())

	if s.config.EnableAuth {
		engine.Use(s.authMiddleware())
	}

	engine.GET("/health", s.handleHealth)

	v1 := engine.Group("/v1")
	v1.POST("/agent-runtime", s.handleAgentRuntimeCreate)
	v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleAgentRuntimeDelete)
	v1.POST("/code-interpreter", s.handleCodeInterpreterCreate)
	v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleCodeInterpreterDelete)

	s.httpServer = &http.Server{
		Addr:         fmt.Sprintf(":%d", s.config.Port),
		Handler:      engine,
		ReadTimeout:  15 * time.Second,
		IdleTimeout:  90 * time.Second,
		WriteTimeout: 60 * time.Second,
	}
}

func (s *Server) Start() error {
	s.gcWg.Add(1)
	go s.runGarbageCollector()

	klog.Infof("Starting Workload Manager on port %d", s.config.Port)
	if err := s.httpServer.ListenAndServe(); err != http.ErrServerClosed {
		return fmt.Errorf("http server failed: %w", err)
	}
	return nil
}

func (s *Server) Shutdown(ctx context.Context) error {
	close(s.gcStopChan)
	s.gcWg.Wait()

	if s.httpServer != nil {
		shutdownCtx, cancel := context.WithTimeout(ctx, 15*time.Second)
		defer cancel()
		return s.httpServer.Shutdown(shutdownCtx)
	}
	return nil
}

func (s *Server) Close() error {
	if s.store != nil {
		return s.store.Close()
	}
	return nil
}

