	"time"

	authenticationv1 "k8s.io/api/authentication/v1"
	"k8s.io/klog/v2"
)

type contextKey string

const (
	ContextKeyUserToken        contextKey = "userToken"
	ContextKeyServiceAccount   contextKey = "serviceAccount"
	ContextKeySAName           contextKey = "serviceAccountName"
	ContextKeySANamespace      contextKey = "namespace"
)

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "missing Authorization header"})
			c.Abort()
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "invalid Authorization header format"})
			c.Abort()
			return
		}

		token := parts[1]

		cached, ok := s.authCache.get(token)
		if ok {
			if time.Now().After(cached.expiresAt) {
				s.authCache.delete(token)
			} else {
				c.Set(string(ContextKeyUserToken), cached.token)
				c.Set(string(ContextKeyServiceAccount), cached.username)
				c.Set(string(ContextKeySAName), cached.saName)
				c.Set(string(ContextKeySANamespace), cached.namespace)
				c.Next()
				return
			}
		}

		result, err := s.validateToken(c.Request.Context(), token)
		if err != nil {
			klog.Errorf("token validation failed: %v", err)
			c.JSON(http.StatusUnauthorized, gin.H{"message": "unauthorized"})
			c.Abort()
			return
		}

		if !result.Status.Authenticated {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "unauthorized"})
			c.Abort()
			return
		}

		username := result.Status.User.Username
		saName := ""
		namespace := ""
		if strings.HasPrefix(username, "system:serviceaccount:") {
			parts := strings.Split(username, ":")
			if len(parts) >= 4 {
				namespace = parts[2]
				saName = parts[3]
			}
		}

		s.authCache.set(token, &AuthCacheEntry{
			token:     token,
			username:  username,
			saName:    saName,
			namespace: namespace,
			expiresAt: time.Now().Add(s.authCache.ttl),
		})

		c.Set(string(ContextKeyUserToken), token)
		c.Set(string(ContextKeyServiceAccount), username)
		c.Set(string(ContextKeySAName), saName)
		c.Set(string(ContextKeySANamespace), namespace)

		c.Next()
	}
}

func (s *Server) validateToken(ctx context.Context, token string) (*authenticationv1.TokenReview, error) {
	tr := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := s.k8sClient.AuthenticationV1().TokenReviews().Create(ctx, tr, metav1.CreateOptions{})
	if err != nil {
		return nil, fmt.Errorf("failed to create token review: %w", err)
	}

	return result, nil
}

func (ac *AuthCache) get(token string) (*AuthCacheEntry, bool) {
	ac.mu.RLock()
	defer ac.mu.RUnlock()
	entry, ok := ac.cache[token]
	return entry, ok
}

func (ac *AuthCache) set(token string, entry *AuthCacheEntry) {
	ac.mu.Lock()
	defer ac.mu.Unlock()
	ac.cache[token] = entry
}

func (ac *AuthCache) delete(token string) {
	ac.mu.Lock()
	defer ac.mu.Unlock()
	delete(ac.cache, token)
}

