package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"time"

	"github.com/agentcube/agentcube/pkg/api"
	"github.com/agentcube/agentcube/pkg/apis/runtime/v1alpha1"
	"github.com/agentcube/agentcube/pkg/store"
	"github.com/gin-gonic/gin"
	"github.com/google/uuid"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
	"k8s.io/klog/v2"
)

type CreateRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

type CreateResponse struct {
	SessionID    string              `json:"sessionId"`
	SandboxID    string              `json:"sandboxId"`
	SandboxName  string              `json:"sandboxName"`
	EntryPoints  []store.EntryPoint  `json:"entryPoints"`
}

type DeleteResponse struct {
	Message string `json:"message"`
}

type ErrorResponse struct {
	Message string `json:"message"`
	Error   string `json:"error,omitempty"`
	Code    int    `json:"code,omitempty"`
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	var req CreateRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: fmt.Sprintf("invalid JSON: %v", err)})
		return
	}

	if req.Namespace == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: "namespace is required"})
		return
	}

	if req.Name == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: "name is required"})
		return
	}

	sessionID := uuid.New().String()
	sandboxID := uuid.New().String()
	sandboxName := fmt.Sprintf("sandbox-%s", sandboxID[:8])

	sandbox := &unstructured.Unstructured{
		Object: map[string]interface{}{
			"apiVersion": "runtime.agentcube.volcano.sh/v1alpha1",
			"kind":       "AgentRuntime",
			"metadata": map[string]interface{}{
				"name":      sandboxName,
				"namespace": req.Namespace,
				"labels": map[string]interface{}{
					"app.kubernetes.io/managed-by": "workload-manager",
					"agentcube/session-id":         sessionID,
				},
			},
			"spec": map[string]interface{}{
				"sessionTimeout":     "15m",
				"maxSessionDuration": "8h",
			},
		},
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), s.config.WatchTimeout)
	defer cancel()

	created, err := s.dynamicClient.Resource(v1alpha1.GroupVersion.WithResource("agentruntimes")).Namespace(req.Namespace).Create(ctx, sandbox, metav1.CreateOptions{})
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{Message: fmt.Sprintf("failed to create sandbox: %v", err), Error: err.Error()})
		return
	}

	sandboxInfo := &store.SandboxInfo{
		SessionID:   sessionID,
		SandboxID:   created.GetName(),
		SandboxName: created.GetName(),
		Kind:        "AgentRuntime",
		Namespace:   req.Namespace,
		CreatedAt:   time.Now(),
		ExpiresAt:   time.Now().Add(8 * time.Hour),
		EntryPoints: []store.EntryPoint{},
	}

	if err := s.store.StoreSandbox(c.Request.Context(), sandboxInfo); err != nil {
		s.deleteSandbox(ctx, req.Namespace, created.GetName(), "AgentRuntime")
		c.JSON(http.StatusInternalServerError, ErrorResponse{Message: fmt.Sprintf("failed to store session: %v", err), Error: err.Error()})
		return
	}

	c.JSON(http.StatusOK, CreateResponse{
		SessionID:   sessionID,
		SandboxID:   created.GetName(),
		SandboxName: created.GetName(),
		EntryPoints: []store.EntryPoint{},
	})
}

func (s *Server) handleAgentRuntimeDelete(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: "sessionId is required"})
		return
	}

	sandboxInfo, err := s.store.GetSandboxBySessionID(c.Request.Context(), sessionID)
	if err != nil {
		c.JSON(http.StatusOK, DeleteResponse{Message: "Sandbox deleted successfully"})
		return
	}

	ctx := c.Request.Context()
	if err := s.deleteSandbox(ctx, sandboxInfo.Namespace, sandboxInfo.SandboxID, sandboxInfo.Kind); err != nil {
		klog.Errorf("failed to delete sandbox: %v", err)
	}

	if err := s.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		klog.Errorf("failed to delete from store: %v", err)
	}

	c.JSON(http.StatusOK, DeleteResponse{Message: "Sandbox deleted successfully"})
}

func (s *Server) handleCodeInterpreterCreate(c *gin.Context) {
	var req CreateRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: fmt.Sprintf("invalid JSON: %v", err)})
		return
	}

	if req.Namespace == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: "namespace is required"})
		return
	}

	if req.Name == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: "name is required"})
		return
	}

	sessionID := uuid.New().String()
	sandboxID := uuid.New().String()
	sandboxName := fmt.Sprintf("ci-sandbox-%s", sandboxID[:8])

	sandbox := &unstructured.Unstructured{
		Object: map[string]interface{}{
			"apiVersion": "runtime.agentcube.volcano.sh/v1alpha1",
			"kind":       "CodeInterpreter",
			"metadata": map[string]interface{}{
				"name":      sandboxName,
				"namespace": req.Namespace,
				"labels": map[string]interface{}{
					"app.kubernetes.io/managed-by": "workload-manager",
					"agentcube/session-id":         sessionID,
				},
			},
			"spec": map[string]interface{}{
				"sessionTimeout": "15m",
				"authMode":       "picod",
