func (s *Server) runGarbageCollector() {
	defer s.gcWg.Done()

	ticker := time.NewTicker(s.config.GCTickInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			s.cleanupExpiredSandboxes()
			s.cleanupInactiveSandboxes()
		case <-s.gcStopChan:
			klog.Info("garbage collector shutting down")
			return
		}
	}
}

func (s *Server) cleanupExpiredSandboxes() {
	ctx := context.Background()
	before := time.Now()

	expired, err := s.store.ListExpiredSandboxes(ctx, before, 16)
	if err != nil {
		klog.Errorf("failed to list expired sandboxes: %v", err)
		return
	}

	for _, sandbox := range expired {
		klog.Infof("deleting expired sandbox %s/%s (session: %s)", sandbox.Namespace, sandbox.SandboxID, sandbox.SessionID)
		if err := s.deleteSandbox(ctx, sandbox.Namespace, sandbox.SandboxID, sandbox.Kind); err != nil {
			klog.Errorf("failed to delete sandbox %s: %v", sandbox.SandboxID, err)
			continue
		}

		if err := s.store.DeleteSandboxBySessionID(ctx, sandbox.SessionID); err != nil {
