	"time"

	"github.com/agentcube/agentcube/pkg/store"
	"github.com/gin-gonic/gin"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestServer_HealthEndpoint(t *testing.T) {
	gin.SetMode(gin.TestMode)

	config := NewConfig()
	config.Port = 0

	server := &Server{
		config: config,
	}
	server.setupRouter()

	req := httptest.NewRequest(http.MethodGet, "/health", nil)
	w := httptest.NewRecorder()

	server.httpServer.Handler.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)
	assert.Contains(t, w.Body.String(), "healthy")
}

func TestServer_AuthMiddleware_MissingToken(t *testing.T) {
	gin.SetMode(gin.TestMode)

	config := NewConfig()
	config.EnableAuth = true

	server := &Server{
		config: config,
		authCache: &AuthCache{
			cache: make(map[string]*AuthCacheEntry),
			ttl:   5 * time.Minute,
		},
	}
	server.setupRouter()

	req := httptest.NewRequest(http.MethodPost, "/v1/agent-runtime", nil)
	w := httptest.NewRecorder()

	server.httpServer.Handler.ServeHTTP(w, req)

	assert.Equal(t, http.StatusUnauthorized, w.Code)
	assert.Contains(t, w.Body.String(), "missing Authorization header")
}

func TestServer_AuthMiddleware_InvalidTokenFormat(t *testing.T) {
	gin.SetMode(gin.TestMode)

	config := NewConfig()
	config.EnableAuth = true

	server := &Server{
		config: config,
		authCache: &AuthCache{
			cache: make(map[string]*AuthCacheEntry),
			ttl:   5 * time.Minute,
		},
	}
	server.setupRouter()

	req := httptest.NewRequest(http.MethodPost, "/v1/agent-runtime", nil)
	req.Header.Set("Authorization", "Invalid token")
	w := httptest.NewRecorder()

	server.httpServer.Handler.ServeHTTP(w, req)

	assert.Equal(t, http.StatusUnauthorized, w.Code)
	assert.Contains(t, w.Body.String(), "invalid Authorization header format")
}

func TestServer_CreateRequest_EmptyNamespace(t *testing.T) {
	gin.SetMode(gin.TestMode)

	config := NewConfig()
	config.EnableAuth = false

	server := &Server{
		config: config,
		authCache: &AuthCache{
			cache: make(map[string]*AuthCacheEntry),
			ttl:   5 * time.Minute,
		},
	}
	server.setupRouter()

	reqBody := CreateRequest{
		Kind: "AgentRuntime",
		Name: "test-runtime",
	}
	body, _ := json.Marshal(reqBody)

	req := httptest.NewRequest(http.MethodPost, "/v1/agent-runtime", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	server.httpServer.Handler.ServeHTTP(w, req)

	assert.Equal(t, http.StatusBadRequest, w.Code)
	assert.Contains(t, w.Body.String(), "namespace is required")
}

func TestServer_CreateRequest_EmptyName(t *testing.T) {
	gin.SetMode(gin.TestMode)

	config := NewConfig()
	config.EnableAuth = false

	server := &Server{
		config: config,
		authCache: &AuthCache{
			cache: make(map[string]*AuthCacheEntry),
			ttl:   5 * time.Minute,
		},
	}
	server.setupRouter()

	reqBody := CreateRequest{
		Kind:      "AgentRuntime",
		Namespace: "default",
	}
	body, _ := json.Marshal(reqBody)

	req := httptest.NewRequest(http.MethodPost, "/v1/agent-runtime", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	server.httpServer.Handler.ServeHTTP(w, req)

	assert.Equal(t, http.StatusBadRequest, w.Code)
	assert.Contains(t, w.Body.String(), "name is required")
}

func TestServer_DeleteRequest_MissingSessionID(t *testing.T) {
	gin.SetMode(gin.TestMode)

	config := NewConfig()
	config.EnableAuth = false

	server := &Server{
		config: config,
		authCache: &AuthCache{
			cache: make(map[string]*AuthCacheEntry),
			ttl:   5 * time.Minute,
		},
	}
	server.setupRouter()

	req := httptest.NewRequest(http.MethodDelete, "/v1/agent-runtime/sessions/", nil)
	w := httptest.NewRecorder()

	server.httpServer.Handler.ServeHTTP(w, req)

	assert.Equal(t, http.StatusBadRequest, w.Code)
	assert.Contains(t, w.Body.String(), "sessionId is required")
}

func TestAuthCache_GetSet(t *testing.T) {
	cache := &AuthCache{
		cache: make(map[string]*AuthCacheEntry),
		ttl:   5 * time.Minute,
	}

	token := "test-token"
	entry := &AuthCacheEntry{
		token:     token,
		username:  "test-user",
		saName:    "test-sa",
		namespace: "default",
		expiresAt: time.Now().Add(5 * time.Minute),
	}

	cache.set(token, entry)

	got, ok := cache.get(token)
	require.True(t, ok)
	assert.Equal(t, entry.username, got.username)
	assert.Equal(t, entry.saName, got.saName)
	assert.Equal(t, entry.namespace, got.namespace)
}

func TestAuthCache_Delete(t *testing.T) {
	cache := &AuthCache{
		cache: make(map[string]*AuthCacheEntry),
		ttl:   5 * time.Minute,
	}

	token := "test-token"
	cache.set(token, &AuthCacheEntry{
		token:     token,
		username:  "test-user",
		expiresAt: time.Now().Add(5 * time.Minute),
	})

	cache.delete(token)

	_, ok := cache.get(token)
	assert.False(t, ok)
}

func TestAuthCache_GetExpired(t *testing.T) {
	cache := &AuthCache{
		cache: make(map[string]*AuthCacheEntry),
		ttl:   5 * time.Minute,
	}

	token := "test-token"
	cache.set(token, &AuthCacheEntry{
		token:     token,
		username:  "test-user",
		expiresAt: time.Now().Add(-1 * time.Minute),
	})

	entry, ok := cache.get(token)
	require.True(t, ok)
	assert.True(t, time.Now().After(entry.expiresAt))
}

func TestCreateResponse_JSON(t *testing.T) {
	response := CreateResponse{
		SessionID:   "test-session",
		SandboxID:   "test-sandbox",
		SandboxName: "sandbox-test",
		EntryPoints: []store.EntryPoint{
			{
				Path:     "/api",
				Protocol: "http",
				Endpoint: "10.0.0.1:8080",
				Name:     "main",
			},
		},
	}

	data, err := json.Marshal(response)
	require.NoError(t, err)

	var decoded CreateResponse
	err = json.Unmarshal(data, &decoded)
	require.NoError(t, err)

	assert.Equal(t, response.SessionID, decoded.SessionID)
	assert.Equal(t, response.SandboxID, decoded.SandboxID)
	assert.Len(t, decoded.EntryPoints, 1)
}

func TestDeleteResponse_JSON(t *testing.T) {
	response := DeleteResponse{
		Message: "Sandbox deleted successfully",
	}

	data, err := json.Marshal(response)
	require.NoError(t, err)

	var decoded DeleteResponse
	err = json.Unmarshal(data, &decoded)
	require.NoError(t, err)

	assert.Equal(t, response.Message, decoded.Message)
}

func TestErrorResponse_JSON(t *testing.T) {
	response := ErrorResponse{
		Message: "test error",
		Error:   "detailed error",
		Code:    400,
	}

	data, err := json.Marshal(response)
	require.NoError(t, err)

	var decoded ErrorResponse
	err = json.Unmarshal(data, &decoded)
	require.NoError(t, err)

	assert.Equal(t, response.Message, decoded.Message)
	assert.Equal(t, response.Error, decoded.Error)
	assert.Equal(t, response.Code, decoded.Code)
}

package main

import (
	"context"
	"flag"
	"fmt"
	"os"
	"os/signal"
	"syscall"

	"github.com/agentcube/agentcube/pkg/workloadmanager"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(nil)
	flag.Parse()

	config := workloadmanager.NewConfig()
	config.AddFlags(flag.CommandLine)
	flag.Parse()

	server, err := workloadmanager.NewServer(config)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	errChan := make(chan error, 1)
	go func() {
		if err := server.Start(); err != nil {
			errChan <- fmt.Errorf("server error: %w", err)
		}
	}()

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	select {
	case err := <-errChan:
		klog.Fatalf("Server error: %v", err)
	case <-sigChan:
		klog.Info("Received shutdown signal")
	}

	klog.Info("Shutting down Workload Manager")
	if err := server.Shutdown(context.Background()); err != nil {
		klog.Errorf("Error during shutdown: %v", err)
	}

	if err := server.Close(); err != nil {
		klog.Errorf("Error closing store: %v", err)
	}

	klog.Info("Workload Manager stopped")
}

