package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"sync"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"k8s.io/klog/v2"
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	mu         sync.RWMutex
}

type Claims struct {
	jwt.RegisteredClaims
	SessionID string `json:"sessionId"`
	Kind      string `json:"kind"`
	Namespace string `json:"namespace"`
}

func NewJWTManager() *JWTManager {
	return &JWTManager{}
}

func (m *JWTManager) GenerateKeys() error {
	m.mu.Lock()
	defer m.mu.Unlock()

	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return fmt.Errorf("failed to generate private key: %w", err)
	}

	m.privateKey = privateKey
	m.publicKey = &privateKey.PublicKey

	return nil
}

func (m *JWTManager) GenerateToken(sessionID, kind, namespace string, expiry time.Duration) (string, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if m.privateKey == nil {
		return "", fmt.Errorf("private key not initialized")
	}

	claims := &Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(expiry)),
			IssuedAt:  jwt.NewNumericDate(time.Now()),
			NotBefore: jwt.NewNumericDate(time.Now()),
		},
		SessionID: sessionID,
		Kind:      kind,
		Namespace: namespace,
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	signed, err := token.SignedString(m.privateKey)
	if err != nil {
		return "", fmt.Errorf("failed to sign token: %w", err)
	}

	return signed, nil
}

func (m *JWTManager) ValidateToken(tokenString string) (*Claims, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if m.publicKey == nil {
		return nil, fmt.Errorf("public key not initialized")
	}

	token, err := jwt.ParseWithClaims(tokenString, &Claims{}, func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return m.publicKey, nil
	}, jwt.WithLeeway(1*time.Minute))

	if err != nil {
		return nil, fmt.Errorf("failed to parse token: %w", err)
	}

	claims, ok := token.Claims.(*Claims)
	if !ok || !token.Valid {
		return nil, fmt.Errorf("invalid token claims")
	}

	return claims, nil
}

func (m *JWTManager) GetPublicKeyPEM() ([]byte, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if m.publicKey == nil {
		return nil, fmt.Errorf("public key not initialized")
	}

	pubASN1, err := x509.MarshalPKIXPublicKey(m.publicKey)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal public key: %w", err)
	}

	pemBytes := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: pubASN1,
	})

	return pemBytes, nil
}

func (m *JWTManager) GetPrivateKeyPEM() ([]byte, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if m.privateKey == nil {
		return nil, fmt.Errorf("private key not initialized")
	}

	privASN1 := x509.MarshalPKCS1PrivateKey(m.privateKey)
	pemBytes := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: privASN1,
	})

	return pemBytes, nil
}

func (m *JWTManager) TryStoreOrLoadJWTKeySecret(namespace string) error {
	privateKeyPath := fmt.Sprintf("/etc/agentcube/keys/private.pem")
	publicKeyPath := fmt.Sprintf("/etc/agentcube/keys/public.pem")

	_, errPrivate := os.Stat(privateKeyPath)
	_, errPublic := os.Stat(publicKeyPath)

	if errPrivate == nil && errPublic == nil {
		privateData, err := os.ReadFile(privateKeyPath)
		if err != nil {
			return fmt.Errorf("failed to read private key: %w", err)
		}

		publicData, err := os.ReadFile(publicKeyPath)
		if err != nil {
			return fmt.Errorf("failed to read public key: %w", err)
		}

		return m.LoadKeysFromPEM(privateData, publicData)
	}

	if err := m.GenerateKeys(); err != nil {
		return fmt.Errorf("failed to generate keys: %w", err)
	}

	privatePEM, err := m.GetPrivateKeyPEM()
	if err != nil {
		return err
	}

	publicPEM, err := m.GetPublicKeyPEM()
	if err != nil {
		return err
	}

	keysDir := "/etc/agentcube/keys"
	if err := os.MkdirAll(keysDir, 0755); err != nil {
		klog.Warningf("failed to create keys directory: %v", err)
	}

	os.WriteFile(privateKeyPath, privatePEM, 0600)
	os.WriteFile(publicKeyPath, publicPEM, 0644)

	klog.Infof("Generated and stored JWT keys in %s", keysDir)
	return nil
}

func (m *JWTManager) LoadKeysFromPEM(privatePEM, publicPEM []byte) error {
	privBlock, _ := pem.Decode(privatePEM)
	if privBlock == nil {
		return fmt.Errorf("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	pubBlock, _ := pem.Decode(publicPEM)
	if pubBlock == nil {
		return fmt.Errorf("failed to decode public key PEM")
	}

	publicKey, err := x509.ParsePKIXPublicKey(pubBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	rsaPubKey, ok := publicKey.(*rsa.PublicKey)
	if !ok {
		return fmt.Errorf("public key is not RSA")
	}

	m.mu.Lock()
	m.privateKey = privateKey
	m.publicKey = rsaPubKey
	m.mu.Unlock()

	klog.Info("Loaded JWT keys from PEM")
	return nil
}

func (m *JWTManager) GetPrivateKey() *rsa.PrivateKey {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.privateKey
}

func (m *JWTManager) GetPublicKey() *rsa.PublicKey {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.publicKey
}

